(function () {
    var val = getValue('email_kp@$ROW$');

    if (!val) return false;

    // trim check
    if (val !== val.trim()) return true;

    var email = val.toLowerCase();

    // tidak boleh ada double dot
    if (email.includes('..')) return true;

    // regex email lebih strict
    var pattern = /^[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$/;

    // harus match format dasar
    if (!pattern.test(email)) return true;

    // pecah local dan domain
    var parts = email.split('@');

    if (parts.length !== 2) return true;

    var local = parts[0];
    var domain = parts[1];

    // local/domain tidak boleh diawali/diakhiri titik
    if (
        local.startsWith('.') ||
        local.endsWith('.') ||
        domain.startsWith('.') ||
        domain.endsWith('.')
    ) {
        return true;
    }

    // TLD minimal 2 karakter
    var domainParts = domain.split('.');
    var tld = domainParts[domainParts.length - 1];

    if (tld.length < 2) return true;

    return false;
})();

