(function () {
  var val = getValue('id_pelanggan@$ROW$');

  if (!val) return false;

  // jika 9999, tidak perlu divalidasi
  if (val === '9999') return false;

  // tidak boleh ada spasi di awal/akhir
  if (val !== val.trim()) return true;

  // harus 11–12 digit angka
  return !/^[0-9]{11,13}$/.test(val);
})();

